import Link from "next/link";
import { getTranslations } from "next-intl/server";
import { AppShell } from "@/components/app-shell";
import { KnowledgeForm } from "@/components/knowledge/knowledge-form";
import { getAuthContext } from "@/lib/firebase/auth";
import { knowledgeRepository } from "@/lib/repositories/knowledge-repository";

export default async function Page() {
  const common = await getTranslations("Common");
  const t = await getTranslations("Knowledge");
  const auth = await getAuthContext();
  if (!auth?.workspaceId) {
    return <AppShell section="knowledge"><p>{common("unauthenticated")}</p></AppShell>;
  }

  const items = await knowledgeRepository.list(auth.workspaceId);

  return (
    <AppShell section="knowledge">
      <div className="content-stack space-y-6">
        <section className="app-card"><KnowledgeForm /></section>
        <section className="list-grid">
          {items.map((item) => (
            <article key={item.id} className="list-card">
              <div className="list-card-header">
                <div>
                  <h2 className="font-semibold">{item.title}</h2>
                  <p className="mt-1 text-sm muted">{item.body || t("noContent")}</p>
                </div>
                <Link href={`/knowledge/${item.id}`} className="pill-link">{t("viewDetail")}</Link>
              </div>
            </article>
          ))}
          {items.length === 0 ? <p className="empty-state">{t("empty")}</p> : null}
        </section>
      </div>
    </AppShell>
  );
}
